def nlmsg_next(nlh, remaining):

    totlen = libnl.linux_private.netlink.NLMSG_ALIGN(nlh.nlmsg_len)
    remaining.value -= totlen
    return libnl.linux_private.netlink.nlmsghdr(bytearray_ptr(nlh.bytearray, totlen))

