def rfft(a, n=None, axis=-1, norm=None):

    unitary = _unitary(norm)
    if unitary and n is None:
        a = asarray(a)
        n = a.shape[axis]
    output = mkl_fft.rfft_numpy(a, n=n, axis=axis)
    if unitary:
        output *= 1 / sqrt(n)
    return output

