def entropy_of_antennas(positions, normalize=False):

    counter = Counter(p for p in positions)
    raw_entropy = entropy(list(counter.values()))
    n = len(counter)
    if normalize and n > 1:
        return raw_entropy / math.log(n)
    else:
        return raw_entropy

